```@staff_member_required
def config_view(request):
    if not request.user.is_superuser:
        raise Http404

    if request.method == 'POST':
        form = LMSConfigForm(data=request.POST)

        if form.is_valid():
            active_semester_id = form.cleaned_data['lms_active_semester']
